for (const item of $input.all()) {
  // 1. Viajamos al nodo 'Aggregate' para traer el array original separado por mensajes
  const arrayMensajes = $('Juntar MSG').first().json.message;

  if (arrayMensajes && Array.isArray(arrayMensajes)) {
    // 2. Filtramos mágicamente: guardamos todo EXCEPTO lo que contenga la palabra "[IMAGEN]"
    const soloTextoUsuario = arrayMensajes.filter(mensaje => !mensaje.includes('[IMAGEN]'));

    // 3. Ahora sí, concatenamos pero solo los mensajes reales del cliente
    item.json.mensaje_limpio = soloTextoUsuario.join(" ").trim();
  } else {
    // Fallback de seguridad
    item.json.mensaje_limpio = $('Juntar MSG').first().json.mensaje; 
  }
}

return $input.all();

const items = $input.all();

return items.map((item) => {
  let text = item.json.output || "";
  let textLower = text.toLowerCase();

  // 1. Detección por coincidencia de frases exactas
  const fraseVenta1 = "perfecto, entre los proximos 2 dias habiles se contactara un diseñador con vos";
  const fraseVenta2 = "perfecto, en el proximo dia habil se contactara un diseñador con vos";
  const fraseReunion = "genial, te esperamos en la reunion";

  // Evaluamos si contiene alguna de las dos frases de venta
  let esVenta = textLower.includes(fraseVenta1) || textLower.includes(fraseVenta2);

  // Evaluamos si contiene la frase de reunión
  let esReunion = textLower.includes(fraseReunion);

  // 2. Evaluamos si debe cerrar el chat
  item.json.should_close = esVenta || esReunion;

  // 3. Asignamos la etiqueta dinámica para Chatwoot
  if (esReunion) {
      item.json.etiqueta_cierre = "reunion";
  } else if (esVenta) {
      item.json.etiqueta_cierre = "venta";
  }

  // 4. Limpieza del texto final
  let cleanOutput = text
    .replace(/\n{3,}/g, '\n\n') // Limpieza de saltos de línea extra
    .trim(); 

  item.json.output = cleanOutput;

  // 5. ARMAMOS EL PAYLOAD PARA CHATWOOT ACÁ MISMO
  item.json.chatwoot_payload = {
    content: cleanOutput,
    message_type: "outgoing",
    private: false,
    sender: {
      type: "bot"
    }
  };

  return item;
});
